// Modified: added SEED_VALUE parameter for independent per-channel seeds.
// Galois LFSR: 32-bit, polynomial mask 0xA3000000 (right-shift form).
// Period: 2^32 - 1 = 4294967295 cycles before repeat.

`timescale 1ns/10ps

module lfsr_32 #(parameter [31:0] SEED_VALUE = 32'd448929031) (
    reset,
    clock,
    out
);

input  reset;
input  clock;
output [31:0] out;
wire   [31:0] out;

reg [31:0] reg_internal;

always @(posedge clock, posedge reset) begin: LFSR_32_LFSR_LOGIC
    if (reset == 1) begin
        reg_internal <= SEED_VALUE;
    end else begin
        if (reg_internal[0] == 1)
            reg_internal <= (reg_internal >> 1) ^ 32'hA3000000;
        else
            reg_internal <= (reg_internal >> 1);
    end
end

assign out = reg_internal;

endmodule
